var raw = $input.first().json;
var body = raw.body || raw;

var tenantId = String(body.tenantId || '').replace(/[^a-f0-9-]/gi, '').substring(0, 36);
var email = String(body.email || '').substring(0, 200);
var nom = String(body.nom || '').replace(/'/g, "''").substring(0, 100);
var prenom = String(body.prenom || '').replace(/'/g, "''").substring(0, 100);
var entreprise = String(body.entreprise || '').replace(/'/g, "''").substring(0, 200);
var leadId = String(body.leadId || '').replace(/[^a-f0-9-]/gi, '').substring(0, 36);
var companyName = String(body.companyName || 'TalosPrimes').substring(0, 100);

if (!tenantId || !email) throw new Error('tenantId et email requis');

// Generate token
var token = require('crypto').randomBytes(16).toString('hex');
var avisUrl = 'https://demo.talosprimes.com/avis?token=' + token + '&email=' + encodeURIComponent(email);

// Build HTML email
var htmlBody = '<!DOCTYPE html><html><head><meta charset="utf-8"></head>'
  + '<body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;">'
  + '<div style="text-align:center;margin-bottom:30px;">'
  + '<h1 style="color:#4F46E5;">' + companyName + '</h1>'
  + '</div>'
  + '<h2 style="color:#1F2937;">Votre avis compte pour nous !</h2>'
  + '<p style="color:#4B5563;line-height:1.6;">Bonjour' + (prenom ? ' ' + prenom : '') + ',</p>'
  + '<p style="color:#4B5563;line-height:1.6;">Suite a notre echange, nous aimerions connaitre votre niveau de satisfaction. Cela ne prend que 30 secondes !</p>'
  + '<div style="text-align:center;margin:30px 0;">'
  + '<a href="' + avisUrl + '" style="background-color:#4F46E5;color:#ffffff;padding:14px 28px;text-decoration:none;border-radius:8px;font-weight:bold;display:inline-block;">Donner mon avis</a>'
  + '</div>'
  + '<p style="color:#6B7280;font-size:14px;">Merci pour votre confiance !</p>'
  + '<hr style="border:none;border-top:1px solid #E5E7EB;margin:30px 0;">'
  + '<p style="color:#9CA3AF;font-size:12px;text-align:center;">' + companyName + ' — Plateforme de gestion d\'entreprise</p>'
  + '</body></html>';

var textBody = 'Bonjour' + (prenom ? ' ' + prenom : '') + ',\n\n'
  + 'Suite a notre echange, nous aimerions connaitre votre niveau de satisfaction.\n'
  + 'Donnez votre avis ici : ' + avisUrl + '\n\n'
  + 'Merci pour votre confiance !\n' + companyName;

return [{ json: {
  tenantId, leadId, email, nom, prenom, entreprise, token, avisUrl, companyName,
  subject: 'Votre avis compte - ' + companyName,
  htmlBody, textBody
}}];
